import React, { useState, useEffect } from "react";

const priorities = ["Low", "Medium", "High"];
const statuses = ["Open", "In Progress", "Completed"];

export default function AdminFeatureModal({ feature, onSave, onClose }) {
  // feature is null for add, or an object for edit
  const [form, setForm] = useState({
    title: "",
    description: "",
    priority: "Low",
    status: "Open",
  });
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);

  useEffect(() => {
    if (feature) {
      setForm({
        title: feature.title || "",
        description: feature.description || "",
        priority: feature.priority || "Low",
        status: feature.status || "Open",
      });
      if (feature.image) {
        // For edit, preview existing image
        if (typeof feature.image === "string") {
          setImagePreview(`http://localhost:5000/api/features/images/${feature.image}`);
        }
      }
    }
  }, [feature]);

  const handleImageChange = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setImagePreview(event.target.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave({
      ...form,
      image: imageFile,
    });
  };

  return (
    <div
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        width: "100vw",
        height: "100vh",
        background: "rgba(0, 0, 0, 0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 1001,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        style={{
          background: "#fff",
          borderRadius: 12,
          padding: 32,
          maxWidth: 600,
          width: "90%",
          maxHeight: "80vh",
          overflowY: "auto",
          boxShadow: "0 4px 20px rgba(0, 0, 0, 0.3)",
        }}
      >
        <h2 style={{ fontSize: 24, fontWeight: 700, marginBottom: 24, color: "#222" }}>
          {feature ? "Edit Feature" : "Add New Feature"}
        </h2>
        <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Title */}
          <div>
            <label style={{ display: "block", fontWeight: 600, marginBottom: 6, color: "#333" }}>
              Title
            </label>
            <input
              type="text"
              value={form.title}
              onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))}
              placeholder="Enter feature title"
              style={{
                width: "100%",
                padding: 10,
                border: "1px solid #ddd",
                borderRadius: 6,
                fontFamily: "inherit",
                fontSize: 16,
                boxSizing: "border-box",
              }}
              required
            />
          </div>

          {/* Description */}
          <div>
            <label style={{ display: "block", fontWeight: 600, marginBottom: 6, color: "#333" }}>
              Description
            </label>
            <textarea
              value={form.description}
              onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))}
              placeholder="Enter feature description"
              rows={5}
              style={{
                width: "100%",
                padding: 10,
                border: "1px solid #ddd",
                borderRadius: 6,
                fontFamily: "inherit",
                fontSize: 16,
                boxSizing: "border-box",
                resize: "vertical",
              }}
              required
            />
          </div>

          {/* Priority */}
          <div>
            <label style={{ display: "block", fontWeight: 600, marginBottom: 6, color: "#333" }}>
              Priority
            </label>
            <select
              value={form.priority}
              onChange={(e) => setForm((f) => ({ ...f, priority: e.target.value }))}
              style={{
                width: "100%",
                padding: 10,
                border: "1px solid #ddd",
                borderRadius: 6,
                fontFamily: "inherit",
                fontSize: 16,
                boxSizing: "border-box",
              }}
            >
              {priorities.map((p) => (
                <option key={p} value={p}>
                  {p}
                </option>
              ))}
            </select>
          </div>

          {/* Status */}
          <div>
            <label style={{ display: "block", fontWeight: 600, marginBottom: 6, color: "#333" }}>
              Status
            </label>
            <select
              value={form.status}
              onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
              style={{
                width: "100%",
                padding: 10,
                border: "1px solid #ddd",
                borderRadius: 6,
                fontFamily: "inherit",
                fontSize: 16,
                boxSizing: "border-box",
              }}
            >
              {statuses.map((s) => (
                <option key={s} value={s}>
                  {s}
                </option>
              ))}
            </select>
          </div>

          {/* Image Upload */}
          <div>
            <label style={{ display: "block", fontWeight: 600, marginBottom: 6, color: "#333" }}>
              Image
            </label>
            <input
              type="file"
              accept="image/*"
              onChange={handleImageChange}
              style={{
                width: "100%",
                padding: 8,
                border: "1px solid #ddd",
                borderRadius: 6,
                fontFamily: "inherit",
                fontSize: 14,
                boxSizing: "border-box",
              }}
            />
            {imagePreview && (
              <div style={{ marginTop: 12 }}>
                <img
                  src={imagePreview}
                  alt="Preview"
                  style={{
                    maxWidth: "100%",
                    maxHeight: 200,
                    borderRadius: 6,
                    objectFit: "cover",
                  }}
                />
              </div>
            )}
          </div>

          {/* Buttons */}
          <div style={{ display: "flex", gap: 12, justifyContent: "flex-end", marginTop: 20 }}>
            <button
              type="button"
              onClick={onClose}
              style={{
                padding: "10px 24px",
                border: "1px solid #ddd",
                borderRadius: 6,
                background: "#fff",
                color: "#333",
                fontWeight: 600,
                fontSize: 16,
                cursor: "pointer",
                transition: "all 0.2s",
              }}
              onMouseEnter={(e) => (e.target.style.background = "#f5f5f5")}
              onMouseLeave={(e) => (e.target.style.background = "#fff")}
            >
              Cancel
            </button>
            <button
              type="submit"
              style={{
                padding: "10px 24px",
                border: "none",
                borderRadius: 6,
                background: "#6c63ff",
                color: "#fff",
                fontWeight: 600,
                fontSize: 16,
                cursor: "pointer",
                transition: "all 0.2s",
              }}
              onMouseEnter={(e) => (e.target.style.background = "#5953d4")}
              onMouseLeave={(e) => (e.target.style.background = "#6c63ff")}
            >
              {feature ? "Save Changes" : "Add Feature"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
